// ageDays returns whole days between now and an epoch-seconds timestamp.
// A zero/never timestamp yields the full age since the Unix epoch, which
// surfaces "never backed up" as a very large age rather than 0.
func ageDays(now, then int64) int {
	if then <= 0 {
		return int(now / 86400)
	}
	d := now - then
	if d < 0 {
		d = 0
	}
	return int(d / 86400)
}
